// @mui
import { styled } from '@mui/material/styles'

// components
import Page from 'src/components/Page'
// sections
import { Box, Typography, Stack,  Button,Checkbox,Drawer} from '@mui/material'


import { useLocation, useNavigate } from 'react-router'
import TextField from 'src/components/core/LabeledInput'

import * as Yup from 'yup'
import { useFormik, Form, FormikProvider } from 'formik'
import { useDispatch, useSelector } from 'react-redux'
import Countdown from 'react-countdown'
import Container from 'src/components/Layout/Container'
import Content from 'src/components/Layout/Content'
import FooterBase from 'src/components/Layout/Footer'
import { getClients } from 'src/redux/actions/clientExercise'
import Logo from 'src/assets/figgslogo.png'

// ----------------------------------------------------------------------
import Header from 'src/components/onboarding/header'
import { useState } from 'react'
import { updateFeedback } from 'src/redux/actions/feedback'
import { sendinvitation ,resendinvitation} from 'src/redux/actions/invite'
function WorkoutDayBottomDrawer(props) {
    const [drawerOpen, setDrawerOpen] = useState(false)
    const navigate = useNavigate()
    const dispatch = useDispatch()
    const { state } = useLocation()
    const [confirmed,setConfirmed]=useState(false)
    const InviteSchema = Yup.object().shape({
 
        email:Yup.string().email("enter a valid email").required('Email is required'),
        message: Yup.string().nullable(),

    })
 
    const formik = useFormik({
        initialValues: {
   
            email: props?.item?.email
        },
        validationSchema: InviteSchema,
        onSubmit: async (values, { setErrors, setSubmitting ,resetForm}) => {
        
            dispatch(props?.mode=="Edit"?resendinvitation({_id:props?.item?._id}):sendinvitation(values)).then((res)=>{
            
                dispatch({
                    type: 'UPDATE_FEED',
                    payload: {
                        loading: false,
                        snackbar: true,
                        message:'Invitation sent successfully',
                        severity: 'success',
                    },
                })
                resetForm()
                dispatch(getClients())
                setConfirmed(false)
                setDrawerOpen(false)

            }).catch(err=>{
                console.log(err,"err object")
                if(err.status==403){
                    setErrors({
                        email:err.data.message
                    })
                }
             
            
            })
         
        },
    })

    const {
        errors,
        touched,
        handleSubmit,
        isSubmitting,
        getFieldProps,
        setFieldValue,
        values,
    } = formik

    const toggleDrawer = (isOpen) => (event) => {
        if (
            event &&
            event.type === 'keydown' &&
            (event.key === 'Tab' || event.key === 'Shift')
        ) {
            return
        }
        event.stopPropagation()
        setDrawerOpen(isOpen)
    }


  
    return (
        <div>
              
            <Drawer
                anchor={'bottom'}
                PaperProps={{
                    sx:{
                        borderTopLeftRadius:12,
                        borderTopRightRadius:12
                    }
                   
                }}
                
              
                open={drawerOpen}
                onClose={toggleDrawer(false)}
                onOpen={toggleDrawer(true)}
            >
                
      
                <Box
                    padding={'16px 24px 36px'}
                    style={{
                        borderTopLeftRadius: '8px',
                        borderTopRightRadius: '8px',
                        backgroundColor: '#fff',
                    }}
                >
                      <FormikProvider value={formik}>
                <Form autoComplete="off" noValidate onSubmit={handleSubmit}>
                  
                      
                       
                            <Typography
                                variant="h3"
                                align="left"
                                sx={{ mt: 2 ,mb:1}}
                            >
                                Enter your clients email address
                            </Typography>
                            <Typography color={"text.secondary"}>
                            By entering the clients email address you <br/>
will invite him to your client list
                            </Typography>

                            <Stack spacing={2} mt={2} sx={{ width: '100%' }}>
                                <TextField
                                    fullWidth
                                    placeholder={"Example@email.com"}
                                    disabled={props?.mode=="Edit"}
                                    clabel={
                                        <Typography variant="subtitle1">
                                           Email
                                            {/* <Typography component={"span"} color={"error"}>
                        *
                      </Typography> */}
                                        </Typography>
                                    }
                                    {...getFieldProps('email')}
                                    error={Boolean(
                                        touched.email && errors.email
                                    )}
                                    helperText={
                                        touched.email && errors.email
                                    }
                                />

                                {/* <TextField
                                    fullWidth
                                    placeholder={"Write something"}

                                    clabel={
                                        <Typography variant="subtitle1" sx={{display:"flex",alignItems:"center"}}>
                                            Message <Typography variant='text2' color={"text.secondary"}>
                                               &nbsp; optional
                                            </Typography>
                                
                                        </Typography>
                                    }
                                    multiline
                                    minRows={6}
                                    {...getFieldProps('message')}
                                    error={Boolean(
                                        touched.message && errors.message
                                    )}
                                    helperText={
                                        touched.message && errors.message
                                    }
                                /> */}
                                  
                            </Stack>
                   
                      <Box sx={{width:"100%",mt:6}}>
                            {/* <Box >
                                <Typography sx={{alignItems:"center"}} variant='body2'>
                                    <Checkbox size='small' checked={confirmed} onChange={e=>setConfirmed(e.target.checked)} />
                                I confirm all of the information above is correct.
                                </Typography>
                            </Box> */}
                            <Box display={"flex"} justifyContent={"flex-end"}>
                          {props?.mode=="Edit"?  
                          
                          <Countdown
                          autoStart
                         

   date={new Date().getTime() + (90000 - (new Date().getTime()-new Date(props?.item?.updatedAt).getTime()))}
  // onComplete={() => setCompleted(true)}
   renderer={({
       hours,
       minutes,
       seconds,
       completed,
   }) => {

       if (completed) {
           return(     
            <Button 
                            variant='contained' 
                            type='submit'
                            sx={{px:4}}
                            
                            
                            >Resend</Button>
           )
       }
       else{
           return(
           <Typography variant='"body2' color={"primary"}>
          {minutes}:
           {seconds} until resend
       </Typography>)
       }
   }}
   />
                          
                          :<Button 
                            variant='contained' 
                            type='submit'
                            sx={{px:4}}
                            //disabled={!confirmed}
                            >Send</Button>}
                            </Box>
                            </Box>
                           
                        
                
                </Form>
            </FormikProvider>
                    
                </Box>
            </Drawer>
            <div
                onClick={(e) => {
                   setDrawerOpen(true)
                       
                }}
            >
                {props.children}
            </div>
        </div>
    )
}

export default WorkoutDayBottomDrawer
